import {
	computed,
	toValue,
	watch,
	useTemplateRef,
	onMounted,
} from 'ui.vue3';
import { useNewConnectionState } from '../../composables';
import { SOURCE_PORT_STUB_TELEPORT_NAME, TARGET_PORT_STUB_TELEPORT_NAME } from '../../constants';
import type { UseNewConnectionState, DiagramNewConnection } from '../../composables';
import './new-connection.css';

type CircleCenterPosition = {
	cx: number;
	cy: number;
};

type SourcePortStubContainerStyle = {
	width: string;
	height: string;
};

type TargetPortStubContainerStyle = {
	width: string;
	height: string;
};

type NewConnectionSetup = {
	sourcePortStubTeleportName: string;
	targetPortStubTeleportName: string;
	hasNewConnection: boolean;
	hasSourcePort: Pick<UseNewConnectionState, 'hasSourcePort'>;
	hasTargetPort: Pick<UseNewConnectionState, 'hasTargetPort'>;
	sourcePortLayoutRect: Pick<UseNewConnectionState, 'sourcePortLayoutRect'>;
	targetPortLayoutRect: Pick<UseNewConnectionState, 'targetPortLayoutRect'>;
	newConnectionPathInfo: Pick<UseNewConnectionState, 'newConnectionPathInfo'>;
	newTmpConnectionPathInfo: Pick<UseNewConnectionState, 'newConnectionPathInfo'>;
	newConnectionClassNames: { [string]: boolean };
	pathClassNames: { [string]: boolean };
	tmpPathClassNames: { [string]: boolean };
	circleCursorClassNames: { [string]: boolean };
	sourcePortStubContainerStyle: SourcePortStubContainerStyle;
	targetPortStubContainerStyle: TargetPortStubContainerStyle;
	circleCenterPosition: CircleCenterPosition;
};

const NEW_CONNECTION_CLASS_NAME = {
	base: 'ui-block-diagram-new-connection',
	up: '--up',
};

const PATH_CLASS_NAMES = {
	base: 'ui-block-diagram-new-connection__path',
	error: '--error',
};

const CIRCLE_CURSOR_CLASS_NAMES = {
	base: 'ui-block-diagram-new-connection__cursor',
	error: '--error',
};

const TMP_PATH_CLASS_NAMES = {
	base: 'ui-block-diagram-new-connection__tmp-path',
	error: '--error',
};

// @vue/component
export const NewConnection = {
	name: 'NewConnection',
	props: {
		stubSize: {
			type: Number,
			default: 50,
		},
		duration: {
			type: Number,
			default: 3000,
		},
	},
	// eslint-disable-next-line max-lines-per-function
	setup(props): NewConnectionSetup
	{
		const {
			hasNewConnection,
			hasSourcePort,
			hasTargetPort,
			sourcePortLayoutRect,
			targetPortLayoutRect,
			hasTmpConnection,
			newConnectionPathInfo,
			newTmpConnectionPathInfo,
			newConnection,
			isValid,
		} = useNewConnectionState();
		const tmpPathRef = useTemplateRef('tmpPath');
		let animateTmpPath = null;

		const newConnectionClassNames = computed((): { [string]: boolean } => {
			return {
				[NEW_CONNECTION_CLASS_NAME.base]: true,
				[NEW_CONNECTION_CLASS_NAME.up]: toValue(hasNewConnection),
			};
		});

		const pathClassNames = computed((): { [string]: boolean } => ({
			[PATH_CLASS_NAMES.base]: true,
			[PATH_CLASS_NAMES.error]: !toValue(isValid),
		}));

		const circleCursorClassNames = computed((): { [string]: boolean } => {
			return {
				[CIRCLE_CURSOR_CLASS_NAMES.base]: true,
				[CIRCLE_CURSOR_CLASS_NAMES.error]: !toValue(isValid),
			};
		});

		const tmpPathClassNames = computed((): { [string]: boolean } => ({
			[TMP_PATH_CLASS_NAMES.base]: true,
			[TMP_PATH_CLASS_NAMES.error]: !toValue(isValid),
		}));

		const sourceForeignObjectPosition = computed(() => {
			const { x, y, width, height } = toValue(sourcePortLayoutRect);

			const centerPoint = {
				x: x + (width / 2),
				y: y + (height / 2),
			};

			return {
				x: centerPoint.x - (props.stubSize / 2),
				y: centerPoint.y - (props.stubSize / 2),
			};
		});

		const targetForeignObjectPosition = computed(() => {
			const { x, y, width, height } = toValue(targetPortLayoutRect);

			const centerPoint = {
				x: x + (width / 2),
				y: y + (height / 2),
			};

			return {
				x: centerPoint.x - (props.stubSize / 2),
				y: centerPoint.y - (props.stubSize / 2),
			};
		});

		const stubContainerStyle = computed((): SourcePortStubContainerStyle => {
			return {
				width: `${props.stubSize}px`,
				height: `${props.stubSize}px`,
			};
		});

		const circleCenterPosition = computed((): CircleCenterPosition => {
			return {
				cx: toValue(newConnection)?.center?.x ?? 0,
				cy: toValue(newConnection)?.center?.y ?? 0,
			};
		});

		watch(newConnection, (newValue: DiagramNewConnection | null, oldValue: DiagramNewConnection | null) => {
			const hasNewConnection = newValue !== null;
			const hasEndPoint = hasNewConnection && newValue.end !== null;

			const newPortCompositId = `${newValue?.targetBlockId}_${newValue?.targetPortId}`;
			const oldPortCompositId = `${oldValue?.targetBlockId}_${oldValue?.targetPortId}`;

			const hasNewEndPoint = hasNewConnection
				&& hasEndPoint
				&& newPortCompositId !== oldPortCompositId;

			if (hasNewEndPoint)
			{
				animateTmpPath.cancel();
				animateTmpPath.play();
			}
		}, { deep: true });

		onMounted(() => {
			initAnimateTmpPath();
		});

		function initAnimateTmpPath(): void
		{
			animateTmpPath = toValue(tmpPathRef)?.animate(
				[
					{
						strokeDasharray: '5, 5',
						strokeDashoffset: '100',
					},
					{
						strokeDasharray: '5, 5',
						strokeDashoffset: '0',
					},
				],
				{
					duration: props.duration,
					easing: 'linear',
					iterations: Infinity,
				},
			);
		}

		return {
			SOURCE_PORT_STUB_TELEPORT_NAME,
			TARGET_PORT_STUB_TELEPORT_NAME,
			hasNewConnection,
			hasSourcePort,
			hasTargetPort,
			sourcePortLayoutRect,
			targetPortLayoutRect,
			hasTmpConnection,
			newConnectionPathInfo,
			newTmpConnectionPathInfo,
			newConnectionClassNames,
			pathClassNames,
			tmpPathClassNames,
			circleCursorClassNames,
			stubContainerStyle,
			sourceForeignObjectPosition,
			targetForeignObjectPosition,
			circleCenterPosition,
		};
	},
	template: `
		<svg
			:class="newConnectionClassNames"
		>
			<g
				v-show="hasNewConnection"
				stroke="none"
				stroke-width="1"
				fill="none"
				fill-rule="evenodd"
			>
				<path
					:d="newConnectionPathInfo.path"
					:class="pathClassNames"
				/>

				<path
					ref="tmpPath"
					:d="newTmpConnectionPathInfo.path"
					:class="tmpPathClassNames"
				/>

				<circle
					:cx="circleCenterPosition.cx"
					:cy="circleCenterPosition.cy"
					:r="4"
					:class="circleCursorClassNames"
				/>
			</g>

			<foreignObject
				:x="sourceForeignObjectPosition.x"
				:y="sourceForeignObjectPosition.y"
				:width="stubSize"
				:height="stubSize"
			>
				<div
					:style="stubContainerStyle"
					:id="SOURCE_PORT_STUB_TELEPORT_NAME"
					class="ui-block-diagram-new-connection__port-stub-container"
				/>
			</foreignObject>

			<foreignObject
				:x="targetForeignObjectPosition.x"
				:y="targetForeignObjectPosition.y"
				:width="stubSize"
				:height="stubSize"
			>
				<div
					:style="stubContainerStyle"
					:id="TARGET_PORT_STUB_TELEPORT_NAME"
					class="ui-block-diagram-new-connection__port-stub-container"
				/>
			</foreignObject>
		</svg>
	`,
};
