import { toValue } from 'ui.vue3';
import { KdTree } from '../lib/kd-tree';
import { distance } from './diagram';
import { Point, DiagramPort, DiagramBlock, DiagramBlockId } from '../types';

const PORT_X_KEY = 'x';
const PORT_Y_KEY = 'y';

export class PortsKdTree
{
	#portsKdTree = null;

	init(blocks: DiagramBlock[] = [], portsRectMap = {}): void
	{
		const portsPoint = [];

		for (const block of blocks)
		{
			for (const port of block.ports)
			{
				const { x = 0, y = 0 } = toValue(portsRectMap)
					?.[block.id]
					?.[port.id] ?? {};

				portsPoint.push({
					x,
					y,
					blockId: block.id,
					portId: port.id,
					port: { ...port },
				});
			}
		}

		this.#portsKdTree = new KdTree(
			portsPoint,
			distance,
			[PORT_X_KEY, PORT_Y_KEY],
		);
	}

	insert(point: Point, blockId: DiagramBlockId, port: DiagramPort)
	{
		this.#portsKdTree?.insert({
			...point,
			blockId,
			portId: port.id,
			port: { ...port },
		});
	}

	nearest(point: Point, maxNodes: number = 1, maxDistance: nubmer = 100): []
	{
		return this.#portsKdTree?.nearest(point, maxNodes, maxDistance) ?? [];
	}

	remove(point: Point): void
	{
		return this.#portsKdTree?.remove(point);
	}

	clear(): void
	{
		this.#portsKdTree = null;
	}
}
